function solve(prices, strategy, k) {
    const n = prices.length;
    let originalProfit = 0;
    for (let i = 0; i < n; i++) {
        originalProfit += strategy[i] * prices[i];
    }

    let maxProfit = originalProfit;
    const halfK = k / 2;

    // Precompute the difference if we modify window starting at i
    for (let i = 0; i <= n - k; i++) {
        let currentDiff = 0;
        for (let j = 0; j < halfK; j++) {
            const pos = i + j;
            currentDiff += (0 - strategy[pos]) * prices[pos];
        }
        for (let j = halfK; j < k; j++) {
            const pos = i + j;
            currentDiff += (1 - strategy[pos]) * prices[pos];
        }
        if (currentDiff > 0) {
            maxProfit = Math.max(maxProfit, originalProfit + currentDiff);
        }
    }

    return maxProfit;
}

